package com.securebank.app.model;

import java.io.Serializable;
import java.math.BigDecimal;
import java.util.UUID;

public class TransactionModels {

    public enum TransactionType {
        TRANSFER,
        PAYMENT,
        DEPOSIT,
        WITHDRAWAL
    }

    public enum TransactionStatus {
        PENDING,
        PROCESSING,
        COMPLETED,
        FAILED,
        CANCELLED,
        REQUIRES_ADDITIONAL_AUTH
    }

    public static class Account implements Serializable {
        private final String accountId;
        private final String accountNumber;
        private final String accountName;
        private BigDecimal balance;
        private final String currency;

        public Account(String accountId, String accountNumber, String accountName,
                       BigDecimal balance, String currency) {
            this.accountId = accountId;
            this.accountNumber = accountNumber;
            this.accountName = accountName;
            this.balance = balance;
            this.currency = currency;
        }

        public String getAccountId() { return accountId; }
        public String getAccountNumber() { return accountNumber; }
        public String getAccountName() { return accountName; }
        public BigDecimal getBalance() { return balance; }
        public String getCurrency() { return currency; }

        public String getMaskedAccountNumber() {
            if (accountNumber == null || accountNumber.length() < 4) return "****";
            return "****" + accountNumber.substring(accountNumber.length() - 4);
        }
    }

    public static class TransactionRequest implements Serializable {
        private final String transactionId;
        private final String fromAccountId;
        private final String toAccountId;
        private final BigDecimal amount;
        private final String currency;
        private final TransactionType type;
        private final String description;
        private final long timestamp;
        private String deviceIntegrityToken;
        private String sessionToken;
        private String clientNonce;

        public TransactionRequest(String fromAccountId, String toAccountId,
                                  BigDecimal amount, String currency,
                                  TransactionType type, String description) {
            this.transactionId = UUID.randomUUID().toString();
            this.fromAccountId = fromAccountId;
            this.toAccountId = toAccountId;
            this.amount = amount;
            this.currency = currency;
            this.type = type;
            this.description = description;
            this.timestamp = System.currentTimeMillis();
        }

        public String getTransactionId() { return transactionId; }
        public String getFromAccountId() { return fromAccountId; }
        public String getToAccountId() { return toAccountId; }
        public BigDecimal getAmount() { return amount; }
        public String getCurrency() { return currency; }
        public TransactionType getType() { return type; }
        public String getDescription() { return description; }
        public long getTimestamp() { return timestamp; }

        public void setDeviceIntegrityToken(String token) { this.deviceIntegrityToken = token; }
        public String getDeviceIntegrityToken() { return deviceIntegrityToken; }

        public void setSessionToken(String token) { this.sessionToken = token; }
        public String getSessionToken() { return sessionToken; }

        public void setClientNonce(String nonce) { this.clientNonce = nonce; }
        public String getClientNonce() { return clientNonce; }
    }

    public static class TransactionResponse implements Serializable {
        private final String transactionId;
        private final TransactionStatus status;
        private final String message;
        private final BigDecimal newBalance;
        private final long serverTimestamp;

        public TransactionResponse(String transactionId, TransactionStatus status,
                                   String message, BigDecimal newBalance, long serverTimestamp) {
            this.transactionId = transactionId;
            this.status = status;
            this.message = message;
            this.newBalance = newBalance;
            this.serverTimestamp = serverTimestamp;
        }

        public String getTransactionId() { return transactionId; }
        public TransactionStatus getStatus() { return status; }
        public String getMessage() { return message; }
        public BigDecimal getNewBalance() { return newBalance; }
        public long getServerTimestamp() { return serverTimestamp; }
    }
}


