package com.securebank.app.validation;

import com.securebank.app.model.TransactionModels.TransactionRequest;

import java.math.BigDecimal;
import java.util.ArrayList;
import java.util.List;
import java.util.regex.Pattern;

public class TransactionValidator {

    private static final BigDecimal MIN_AMOUNT = new BigDecimal("0.01");
    private static final BigDecimal MAX_SINGLE_TRANSACTION = new BigDecimal("50000.00");
    private static final BigDecimal MAX_DAILY_LIMIT = new BigDecimal("100000.00");
    private static final Pattern ACCOUNT_ID_PATTERN = Pattern.compile("^[a-zA-Z0-9\\-]{8,36}$");
    private static final Pattern DESCRIPTION_PATTERN = Pattern.compile("^[a-zA-Z0-9\\s.,\\-#/()]{0,140}$");

    public static class ValidationResult {
        private final boolean valid;
        private final List<String> errors;

        public ValidationResult(boolean valid, List<String> errors) {
            this.valid = valid;
            this.errors = errors;
        }

        public boolean isValid() { return valid; }
        public List<String> getErrors() { return errors; }
    }

    public static ValidationResult validate(TransactionRequest request) {
        List<String> errors = new ArrayList<>();

        if (request == null) {
            errors.add("Transaction request cannot be null");
            return new ValidationResult(false, errors);
        }

        // Validate amount
        if (request.getAmount() == null) {
            errors.add("Amount is required");
        } else {
            if (request.getAmount().compareTo(MIN_AMOUNT) < 0) {
                errors.add("Amount must be at least " + MIN_AMOUNT);
            }
            if (request.getAmount().compareTo(MAX_SINGLE_TRANSACTION) > 0) {
                errors.add("Amount exceeds single transaction limit of " + MAX_SINGLE_TRANSACTION);
            }
            if (request.getAmount().scale() > 2) {
                errors.add("Amount cannot have more than 2 decimal places");
            }
        }

        // Validate account IDs
        if (request.getFromAccountId() == null || request.getFromAccountId().isEmpty()) {
            errors.add("Source account is required");
        } else if (!ACCOUNT_ID_PATTERN.matcher(request.getFromAccountId()).matches()) {
            errors.add("Invalid source account format");
        }

        if (request.getToAccountId() == null || request.getToAccountId().isEmpty()) {
            errors.add("Destination account is required");
        } else if (!ACCOUNT_ID_PATTERN.matcher(request.getToAccountId()).matches()) {
            errors.add("Invalid destination account format");
        }

        // Prevent self-transfer
        if (request.getFromAccountId() != null && request.getToAccountId() != null
                && request.getFromAccountId().equals(request.getToAccountId())) {
            errors.add("Cannot transfer to the same account");
        }

        // Validate description (sanitize against injection)
        if (request.getDescription() != null
                && !DESCRIPTION_PATTERN.matcher(request.getDescription()).matches()) {
            errors.add("Description contains invalid characters");
        }

        // Validate currency
        if (request.getCurrency() == null || request.getCurrency().length() != 3) {
            errors.add("Valid 3-letter currency code is required");
        }

        // Validate type
        if (request.getType() == null) {
            errors.add("Transaction type is required");
        }

        return new ValidationResult(errors.isEmpty(), errors);
    }
}


