// BiometricAuthManager.java - Biometric authentication
// ============================================================

package com.securebank.app.security;

import android.content.Context;
import android.util.Log;

import androidx.annotation.NonNull;
import androidx.biometric.BiometricManager;
import androidx.biometric.BiometricPrompt;
import androidx.core.content.ContextCompat;
import androidx.fragment.app.FragmentActivity;

import java.util.concurrent.Executor;

public class BiometricAuthManager {

    private static final String TAG = "BiometricAuthManager";

    public interface BiometricCallback {
        void onSuccess();
        void onFailure(String error);
        void onCancelled();
    }

    public static boolean isBiometricAvailable(Context context) {
        BiometricManager biometricManager = BiometricManager.from(context);
        int result = biometricManager.canAuthenticate(
                BiometricManager.Authenticators.BIOMETRIC_STRONG);
        return result == BiometricManager.BIOMETRIC_SUCCESS;
    }

    public static void authenticate(FragmentActivity activity,
                                    String title,
                                    String subtitle,
                                    BiometricCallback callback) {

        Executor executor = ContextCompat.getMainExecutor(activity);

        BiometricPrompt biometricPrompt = new BiometricPrompt(activity, executor,
                new BiometricPrompt.AuthenticationCallback() {
                    @Override
                    public void onAuthenticationSucceeded(
                            @NonNull BiometricPrompt.AuthenticationResult result) {
                        super.onAuthenticationSucceeded(result);
                        callback.onSuccess();
                    }

                    @Override
                    public void onAuthenticationError(int errorCode,
                                                      @NonNull CharSequence errString) {
                        super.onAuthenticationError(errorCode, errString);
                        if (errorCode == BiometricPrompt.ERROR_USER_CANCELED
                                || errorCode == BiometricPrompt.ERROR_NEGATIVE_BUTTON) {
                            callback.onCancelled();
                        } else {
                            callback.onFailure(errString.toString());
                        }
                    }

                    @Override
                    public void onAuthenticationFailed() {
                        super.onAuthenticationFailed();
                        callback.onFailure("Biometric authentication failed");
                    }
                });

        BiometricPrompt.PromptInfo promptInfo = new BiometricPrompt.PromptInfo.Builder()
                .setTitle(title)
                .setSubtitle(subtitle)
                .setAllowedAuthenticators(
                        BiometricManager.Authenticators.BIOMETRIC_STRONG
                                | BiometricManager.Authenticators.DEVICE_CREDENTIAL)
                .build();

        biometricPrompt.authenticate(promptInfo);
    }
}


// ============================================================
// TransactionProcessor.java - Core transaction orchestration
// ============================================================

package com.securebank.app.transaction;

import android.content.Context;
import android.util.Log;

import com.securebank.app.model.TransactionModels.*;
import com.securebank.app.network.SecureApiClient;
import com.securebank.app.security.SecurityManager;
import com.securebank.app.security.SecurityManager.DeviceIntegrityLevel;
import com.securebank.app.security.SecurityManager.IntegrityCheckResult;
import com.securebank.app.validation.TransactionValidator;
import com.securebank.app.validation.TransactionValidator.ValidationResult;

import java.math.BigDecimal;
import java.util.concurrent.CompletableFuture;

public class TransactionProcessor {

    private static final String TAG = "TransactionProcessor";

    public interface TransactionCallback {
        void onValidationFailed(ValidationResult result);
        void onIntegrityCheckFailed(IntegrityCheckResult result);
        void onBiometricRequired(Runnable onAuthenticated);
        void onTransactionSubmitted(TransactionResponse response);
        void onError(String error);
    }

    private final Context context;
    private final SecurityManager securityManager;
    private final SecureApiClient apiClient;

    public TransactionProcessor(Context context) {
        this.context = context.getApplicationContext();
        this.securityManager = SecurityManager.getInstance(context);
        this.apiClient = new SecureApiClient(context);
    }

    public void processTransaction(TransactionRequest request, TransactionCallback callback) {

        // Step 1: Input validation
        ValidationResult validationResult = TransactionValidator.validate(request);
        if (!validationResult.isValid()) {
            callback.onValidationFailed(validationResult);
            return;
        }

        // Step 2: Device integrity check
        IntegrityCheckResult integrityResult = securityManager.performFullIntegrityCheck();

        if (!integrityResult.areTransactionsAllowed()) {
            Log.w(TAG, "Transaction blocked due to device integrity: "
                    + integrityResult.getFindings());
            callback.onIntegrityCheckFailed(integrityResult);
            return;
        }

        // Step 3: Determine if additional authentication is needed
        boolean requiresBiometric = shouldRequireBiometric(request, integrityResult);

        if (requiresBiometric) {
            callback.onBiometricRequired(() -> {
                executeTransaction(request, integrityResult, callback);
            });
        } else {
            executeTransaction(request, integrityResult, callback);
        }
    }

    private boolean shouldRequireBiometric(TransactionRequest request,
                                           IntegrityCheckResult integrityResult) {
        // Always require biometric for high-value transactions
        if (request.getAmount().compareTo(new BigDecimal("1000.00")) > 0) {
            return true;
        }

        // Require biometric if device is potentially compromised
        if (integrityResult.getLevel() == DeviceIntegrityLevel.POTENTIALLY_COMPROMISED) {
            return true;
        }

        // Require biometric for external transfers
        if (request.getType() == TransactionType.TRANSFER) {
            return true;
        }

        return false;
    }

    private void executeTransaction(TransactionRequest request,
                                    IntegrityCheckResult integrityResult,
                                    TransactionCallback callback) {

        // Step 4: Generate nonce and request Play Integrity token
        String nonce = securityManager.generateNonce();
        request.setClientNonce(nonce);

        securityManager.requestPlayIntegrityToken(nonce)
                .thenCompose(integrityToken -> {
                    request.setDeviceIntegrityToken(integrityToken);

                    // Step 5: Attach session token
                    String sessionToken = securityManager.getSessionToken();
                    if (sessionToken == null) {
                        throw new SecurityException("No active session");
                    }
                    request.setSessionToken(sessionToken);

                    // Step 6: Submit to server
                    return apiClient.submitTransaction(request, sessionToken);
                })
                .thenAccept(response -> {
                    // Step 7: Log transaction result securely
                    logTransactionResult(request, response);
                    callback.onTransactionSubmitted(response);
                })
                .exceptionally(throwable -> {
                    Log.e(TAG, "Transaction processing error", throwable);
                    callback.onError("Transaction failed: " + throwable.getMessage());
                    return null;
                });
    }

    private void logTransactionResult(TransactionRequest request, TransactionResponse response) {
        // Store encrypted audit log locally
        try {
            String logEntry = String.format(
                    "TXN:%s|TYPE:%s|AMT:%s|STATUS:%s|TIME:%d",
                    request.getTransactionId(),
                    request.getType(),
                    request.getAmount().toPlainString(),
                    response.getStatus(),
                    response.getServerTimestamp()
            );

            byte[] encrypted = securityManager.encryptData(logEntry.getBytes("UTF-8"));
            securityManager.storeSecureValue(
                    "txn_log_" + request.getTransactionId(),
                    android.util.Base64.encodeToString(encrypted, android.util.Base64.NO_WRAP)
            );
        } catch (Exception e) {
            Log.e(TAG, "Failed to log transaction", e);
        }
    }
}


// ============================================================
// TransactionActivity.java - Main UI Activity
// ============================================================

package com.securebank.app.ui;

import android.os.Bundle;
import android.view.View;
import android.view.WindowManager;
import android.widget.Button;
import android.widget.EditText;
import android.widget.ProgressBar;
import android.widget.TextView;
import android.widget.Toast;

import androidx.appcompat.app.AlertDialog;
import androidx.appcompat.app.AppCompatActivity;

import com.securebank.app.R;
import com.securebank.app.model.TransactionModels.*;
import com.securebank.app.network.SecureApiClient;
import com.securebank.app.security.BiometricAuthManager;
import com.securebank.app.security.SecurityManager;
import com.securebank.app.security.SecurityManager.IntegrityCheckResult;
import com.securebank.app.transaction.TransactionProcessor;
import com.securebank.app.validation.TransactionValidator.ValidationResult;

import java.math.BigDecimal;
import java.text.NumberFormat;
import java.util.Currency;
import java.util.Locale;

public class TransactionActivity extends AppCompatActivity {

    private SecurityManager securityManager;
    private TransactionProcessor transactionProcessor;
    private SecureApiClient apiClient;

    // UI elements
    private TextView tvAccountName;
    private TextView tvAccountNumber;
    private TextView tvBalance;
    private EditText etRecipientAccount;
    private EditText etAmount;
    private EditText etDescription;
    private Button btnSubmit;
    private ProgressBar progressBar;
    private TextView tvIntegrityStatus;

    private Account currentAccount;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        // Prevent screenshots and screen recording for sensitive financial screens
        getWindow().setFlags(
                WindowManager.LayoutParams.FLAG_SECURE,
                WindowManager.LayoutParams.FLAG_SECURE
        );

        setContentView(R.layout.activity_transaction);

        initializeComponents();
        performStartupSecurityChecks();
        loadAccountData();
    }

    private void initializeComponents() {
        securityManager = SecurityManager.getInstance(this);
        transactionProcessor = new TransactionProcessor(this);
        apiClient = new SecureApiClient(this);

        tvAccountName = findViewById(R.id.tv_account_name);
        tvAccountNumber = findViewById(R.id.tv_account_number);
        tvBalance = findViewById(R.id.tv_balance);
        etRecipientAccount = findViewById(R.id.et_recipient_account);
        etAmount = findViewById(R.id.et_amount);
        etDescription = findViewById(R.id.et_description);
        btnSubmit = findViewById(R.id.btn_submit);
        progressBar = findViewById(R.id.progress_bar);
        tvIntegrityStatus = findViewById(R.id.tv_integrity_status);

        btnSubmit.setOnClickListener(v -> initiateTransaction());
    }

    private void performStartupSecurityChecks() {
        IntegrityCheckResult result = securityManager.performFullIntegrityCheck();

        switch (result.getLevel()) {
            case COMPROMISED:
                showSecurityBlockDialog(result);
                break;

            case POTENTIALLY_COMPROMISED:
                tvIntegrityStatus.setVisibility(View.VISIBLE);
                tvIntegrityStatus.setText("⚠ Enhanced security verification active");
                tvIntegrityStatus.setTextColor(getColor(android.R.color.holo_orange_dark));
                break;

            case TRUSTED:
                tvIntegrityStatus.setVisibility(View.GONE);
                break;

            default:
                tvIntegrityStatus.setVisibility(View.VISIBLE);
                tvIntegrityStatus.setText("⚠ Device verification pending");
                break;
        }
    }

    private void showSecurityBlockDialog(IntegrityCheckResult result) {
        new AlertDialog.Builder(this)
                .setTitle("Security Alert")
                .setMessage("This device does not meet security requirements for financial transactions. " +
                        "Detected issues: " + String.join(", ", result.getFindings()) +
                        "\n\nPlease use a trusted device.")
                .setCancelable(false)
                .setPositiveButton("Exit", (dialog, which) -> {
                    finishAffinity();
                })
                .show();
    }

    private void loadAccountData() {
        showLoading(true);

        String sessionToken = securityManager.getSessionToken();
        if (sessionToken == null) {
            Toast.makeText(this, "Session expired. Please log in again.", Toast.LENGTH_LONG).show();
            // Navigate to login
            finish();
            return;
        }

        // Fetch account from server
        String accountId = getIntent().getStringExtra("account_id");
        if (accountId == null) {
            Toast.makeText(this, "No account selected", Toast.LENGTH_SHORT).show();
            finish();
            return;
        }

        apiClient.fetchAccountBalance(accountId, sessionToken)
                .thenAccept(account -> {
                    runOnUiThread(() -> {
                        showLoading(false);
                        if (account != null) {
                            currentAccount = account;
                            displayAccountInfo(account);
                        } else {
                            Toast.makeText(this, "Failed to load account data",
                                    Toast.LENGTH_SHORT).show();
                        }
                    });
                });
    }

    private void displayAccountInfo(Account account) {
        tvAccountName.setText(account.getAccountName());
        tvAccountNumber.setText("Account: " + account.getMaskedAccountNumber());

        // Format balance with proper currency
        try {
            NumberFormat currencyFormat = NumberFormat.getCurrencyInstance(Locale.US);
            currencyFormat.setCurrency(Currency.getInstance(account.getCurrency()));
            tvBalance.setText(currencyFormat.format(account.getBalance()));
        } catch (Exception e) {
            tvBalance.setText(account.getCurrency() + " " + account.getBalance().toPlainString());
        }
    }

    private void initiateTransaction() {
        if (currentAccount == null) {
            Toast.makeText(this, "Account data not loaded", Toast.LENGTH_SHORT).show();
            return;
        }

        String recipientAccount = etRecipientAccount.getText().toString().trim();
        String amountStr = etAmount.getText().toString().trim();
        String description = etDescription.getText().toString().trim();

        // Basic UI validation
        if (recipientAccount.isEmpty()) {
            etRecipientAccount.setError("Recipient account is required");
            return;
        }

        if (amountStr.isEmpty()) {
            etAmount.setError("Amount is required");
            return;
        }

        BigDecimal amount;
        try {
            amount = new BigDecimal(amountStr);
        } catch (NumberFormatException e) {
            etAmount.setError("Invalid amount");
            return;
        }

        // Create transaction request
        TransactionRequest request = new TransactionRequest(
                currentAccount.getAccountId(),
                recipientAccount,
                amount,
                currentAccount.getCurrency(),
                TransactionType.TRANSFER,
                description
        );

        showLoading(true);
        btnSubmit.setEnabled(false);

        // Process through the secure transaction pipeline
        transactionProcessor.processTransaction(request, new TransactionProcessor.TransactionCallback() {

            @Override
            public void onValidationFailed(ValidationResult result) {
                runOnUiThread(() -> {
                    showLoading(false);
                    btnSubmit.setEnabled(true);

                    StringBuilder errors = new StringBuilder();
                    for (String error : result.getErrors()) {
                        errors.append("• ").append(error).append("\n");
                    }

                    new AlertDialog.Builder(TransactionActivity.this)
                            .setTitle("Validation Error")
                            .setMessage(errors.toString())
                            .setPositiveButton("OK", null)
                            .show();
                });
            }

            @Override
            public void onIntegrityCheckFailed(IntegrityCheckResult result) {
                runOnUiThread(() -> {
                    showLoading(false);
                    btnSubmit.setEnabled(true);
                    showSecurityBlockDialog(result);
                });
            }

            @Override
            public void onBiometricRequired(Runnable onAuthenticated) {
                runOnUiThread(() -> {
                    if (BiometricAuthManager.isBiometricAvailable(TransactionActivity.this)) {
                        BiometricAuthManager.authenticate(
                                TransactionActivity.this,
                                "Authorize Transaction",
                                "Verify your identity to complete this transfer",
                                new BiometricAuthManager.BiometricCallback() {
                                    @Override
                                    public void onSuccess() {
                                        onAuthenticated.run();
                                    }

                                    @Override
                                    public void onFailure(String error) {
                                        showLoading(false);
                                        btnSubmit.setEnabled(true);
                                        Toast.makeText(TransactionActivity.this,
                                                "Authentication failed: " + error,
                                                Toast.LENGTH_SHORT).show();
                                    }

                                    @Override
                                    public void onCancelled() {
                                        showLoading(false);
                                        btnSubmit.setEnabled(true);
                                    }
                                }
                        );
                    } else {
                        // Fallback: device credential
                        onAuthenticated.run();
                    }
                });
            }

            @Override
            public void onTransactionSubmitted(TransactionResponse response) {
                runOnUiThread(() -> {
                    showLoading(false);
                    btnSubmit.setEnabled(true);

                    if (response.getStatus() == TransactionStatus.COMPLETED
                            || response.getStatus() == TransactionStatus.PROCESSING) {
                        showTransactionSuccess(response);
                    } else {
                        showTransactionFailure(response);
                    }
                });
            }

            @Override
            public void onError(String error) {
                runOnUiThread(() -> {
                    showLoading(false);
                    btnSubmit.setEnabled(true);
                    Toast.makeText(TransactionActivity.this, error, Toast.LENGTH_LONG).show();
                });
            }
        });
    }

    private void showTransactionSuccess(TransactionResponse response) {
        // Update displayed balance
        if (response.getNewBalance() != null && currentAccount != null) {
            try {
                NumberFormat currencyFormat = NumberFormat.getCurrencyInstance(Locale.US);
                currencyFormat.setCurrency(Currency.getInstance(currentAccount.getCurrency()));
                tvBalance.setText(currencyFormat.format(response.getNewBalance()));
            } catch (Exception e) {
                tvBalance.setText(currentAccount.getCurrency() + " "
                        + response.getNewBalance().toPlainString());
            }
        }

        new AlertDialog.Builder(this)
                .setTitle("Transaction Successful")
                .setMessage("Transaction ID: " + response.getTransactionId()
                        + "\nStatus: " + response.getStatus()
                        + "\n\n" + response.getMessage())
                .setPositiveButton("OK", (dialog, which) -> {
                    // Clear form
                    etRecipientAccount.setText("");
                    etAmount.setText("");
                    etDescription.setText("");
                })
                .show();
    }

    private void showTransactionFailure(TransactionResponse response) {
        new AlertDialog.Builder(this)
                .setTitle("Transaction Failed")
                .setMessage("Status: " + response.getStatus()
                        + "\n\n" + response.getMessage())
                .setPositiveButton("OK", null)
                .show();
    }

    private void showLoading(boolean show) {
        progressBar.setVisibility(show ? View.VISIBLE : View.GONE);
    }

    @Override
    protected void onPause() {
        super.onPause();
        // Clear sensitive data from UI when app goes to background
        // The FLAG_SECURE already prevents screenshots
    }

    @Override
    protected void onResume() {
        super.onResume();
        // Re-verify integrity when returning to the app
        performStartupSecurityChecks();
    }

    @Override
    protected void onDestroy() {
        super.onDestroy();
        // Clear sensitive data
        if (etAmount != null) etAmount.setText("");
        if (etRecipientAccount != null) etRecipientAccount.setText("");
    }
}


